) SELECT
    pv.id,
    1,
    'Single Session',
    'Week 1 - Build',
    '[{"workout_name": "Squat Mobility Prep", "type": "flexibility", "duration_minutes": 20, "exercises": [{"name": "Foam Roll Quads", "exercise_library_id": null, "in_library": false, "sets": 2, "reps": 10, "rest_seconds": 0, "weight_guidance": "Slow passes", "equipment": "Foam Roller", "body_part": "Legs", "primary_muscle": "Quadriceps", "secondary_muscles": ["Hip Flexors"], "difficulty": "beginner", "form_cue": "Roll from hip to just above knee, pause on knots", "substitution": "Lacrosse Ball Quad"}, {"name": "Ankle Dorsiflexion Mobilization", "exercise_library_id": null, "in_library": false, "sets": 2, "reps": 10, "rest_seconds": 0, "weight_guidance": "Each side", "equipment": "Bodyweight", "body_part": "Legs", "primary_muscle": "Tibialis Anterior", "secondary_muscles": ["Calves"], "difficulty": "beginner", "form_cue": "Knee over toe, heel stays down", "substitution": "Wall Ankle Stretch"}, {"name": "Deep Squat Hold", "exercise_library_id": null, "in_library": false, "sets": 2, "reps": 1, "rest_seconds": 0, "weight_guidance": "Hold 45s", "equipment": "Bodyweight", "body_part": "Hips", "primary_muscle": "Hip Flexors", "secondary_muscles": ["Adductors", "Glutes"], "difficulty": "beginner", "form_cue": "Elbows push knees out, chest up", "substitution": "Assisted Squat Hold"}, {"name": "Banded Ankle Distraction", "exercise_library_id": null, "in_library": false, "sets": 2, "reps": 10, "rest_seconds": 0, "weight_guidance": "Each side", "equipment": "Resistance Band", "body_part": "Legs", "primary_muscle": "Calves", "secondary_muscles": ["Tibialis Anterior"], "difficulty": "beginner", "form_cue": "Band pulls ankle back, drive knee forward", "substitution": "Wall Ankle Mobilization"}, {"name": "Cossack Squat", "exercise_library_id": null, "in_library": false, "sets": 2, "reps": 6, "rest_seconds": 0, "weight_guidance": "Alternating", "equipment": "Bodyweight", "body_part": "Legs", "primary_muscle": "Adductors", "secondary_muscles": ["Quadriceps", "Glutes"], "difficulty": "intermediate", "form_cue": "Sit deep to one side, straight opposite leg", "substitution": "Lateral Lunge"}, {"name": "World''s Greatest Stretch", "exercise_library_id": null, "in_library": false, "sets": 2, "reps": 5, "rest_seconds": 0, "weight_guidance": "Each side", "equipment": "Bodyweight", "body_part": "Full Body", "primary_muscle": "Hip Flexors", "secondary_muscles": ["Thoracic Spine"], "difficulty": "beginner", "form_cue": "Lunge, rotate, reach to ceiling", "substitution": "Spiderman Stretch"}]}]'::jsonb,
    'Squat Mobility Prep',
